      }
    ],
    createdAt: '2023-07-14T16:20:00.000Z'
  }
];

// Mock forum service
const forumService = {
  // Get all forum posts
  getForumPosts: async () => {
    // Simulate API call
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve(forumPosts);
      }, 500);
    });
  },

  // Get a specific forum post by ID
  getForumPostById: async (id) => {
    // Simulate API call
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        const post = forumPosts.find(post => post._id === id);
        if (post) {
          resolve(post);
        } else {
          reject(new Error('Post not found'));
        }
      }, 500);
    });
  },

  // Create a new forum post
  createForumPost: async (postData, token) => {
    // Create new post
    const newPost = {
      _id: Date.now().toString(),
      ...postData,
      user: {
        _id: '1',
        name: 'Rajesh Kumar' // Simulating logged-in user
      },
      comments: [],
      createdAt: new Date().toISOString()
    };
    
    // Simulate API call
    return new Promise((resolve) => {
      setTimeout(() => {
        forumPosts.unshift(newPost);
        resolve(newPost);
      }, 500);
    });
  },

  // Delete a forum post
  deleteForumPost: async (id, token) => {
    // Simulate API call
    return new Promise((resolve) => {
      setTimeout(() => {
        forumPosts = forumPosts.filter(post => post._id !== id);
        resolve({ success: true });
      }, 500);
    });
  },

  // Add a comment to a post
  addComment: async (postId, commentData, token) => {
    // Create new comment
    const newComment = {
      _id: Date.now().toString(),
      comment: commentData.comment,
      commenterId: '1',
      commenterName: 'Rajesh Kumar', // Simulating logged-in user
      createdAt: new Date().toISOString()
    };
    
    // Simulate API call
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        const postIndex = forumPosts.findIndex(post => post._id === postId);
        if (postIndex !== -1) {
          forumPosts[postIndex].comments.push(newComment);
          resolve(forumPosts[postIndex]);
        } else {
          reject(new Error('Post not found'));
        }
      }, 500);
    });
  },

  // Delete a comment
  deleteComment: async (postId, commentId, token) => {
    // Simulate API call
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        const postIndex = forumPosts.findIndex(post => post._id === postId);
        if (postIndex !== -1) {
          forumPosts[postIndex].comments = forumPosts[postIndex].comments.filter(
            comment => comment._id !== commentId
          );
          resolve(forumPosts[postIndex]);
        } else {
          reject(new Error('Post not found'));
        }
      }, 500);
    });
  }
};

export default forumService;
